/**
 * Notifications Component
 * Displays error and success messages
 */

import React, { useEffect, useState } from 'react';
import useWorldBuilderStore from '../store/store.js';

function Notifications() {
  const { error, message, clearError, clearMessage } = useWorldBuilderStore();
  const [visibleError, setVisibleError] = useState(null);
  const [visibleMessage, setVisibleMessage] = useState(null);

  useEffect(() => {
    if (error) {
      setVisibleError(error);
      const timer = setTimeout(() => {
        clearError();
        setVisibleError(null);
      }, 5000);
      return () => clearTimeout(timer);
    }
  }, [error, clearError]);

  useEffect(() => {
    if (message) {
      setVisibleMessage(message);
      const timer = setTimeout(() => {
        clearMessage();
        setVisibleMessage(null);
      }, 4000);
      return () => clearTimeout(timer);
    }
  }, [message, clearMessage]);

  return (
    <div className="notifications-container">
      {visibleError && (
        <div className="notification error">
          <div>
            <strong>⚠️ Error:</strong> {visibleError}
          </div>
          <button
            onClick={() => {
              clearError();
              setVisibleError(null);
            }}
            style={{
              background: 'transparent',
              color: '#721c24',
              border: 'none',
              padding: '0',
              cursor: 'pointer',
              fontSize: '18px',
            }}
          >
            ✕
          </button>
        </div>
      )}

      {visibleMessage && (
        <div className="notification success">
          <div>
            <strong>✓ Success:</strong> {visibleMessage}
          </div>
          <button
            onClick={() => {
              clearMessage();
              setVisibleMessage(null);
            }}
            style={{
              background: 'transparent',
              color: '#155724',
              border: 'none',
              padding: '0',
              cursor: 'pointer',
              fontSize: '18px',
            }}
          >
            ✕
          </button>
        </div>
      )}

      <style>{`
        .notifications-container {
          position: fixed;
          bottom: 20px;
          right: 20px;
          z-index: 1000;
          max-width: 400px;
        }

        .notification {
          padding: 16px;
          margin-bottom: 12px;
          border-radius: 8px;
          display: flex;
          justify-content: space-between;
          align-items: flex-start;
          gap: 12px;
          animation: slideIn 0.3s ease-out;
        }

        @keyframes slideIn {
          from {
            transform: translateX(400px);
            opacity: 0;
          }
          to {
            transform: translateX(0);
            opacity: 1;
          }
        }
      `}</style>
    </div>
  );
}

export default Notifications;
